import { MakeLogicType, actions, afterMount, kea, listeners, path, reducers, selectors } from 'kea'
import { loaders } from 'kea-loaders'

import { lemonToast } from '@posthog/lemon-ui'

import api from 'lib/api'

import { Survey } from '~/types'

const SURVEYS_PAGE_SIZE = 20

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface surveyTriggerLogicValues {
    allSurveys: Survey[]
    filteredSurveys: Survey[]
    hasMoreSurveys: boolean
    moreSurveys: Survey[]
    moreSurveysLoading: boolean
    responseCounts: Record<string, number>
    responseCountsLoading: boolean
    searchTerm: string
    surveys: Survey[]
    surveysLoading: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface surveyTriggerLogicActions {
    loadMoreSurveys: () => any
    loadMoreSurveysFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadMoreSurveysSuccess: (
        moreSurveys: Survey[],
        payload?: any
    ) => {
        moreSurveys: Survey[]
        payload?: any
    }
    loadResponseCounts: () => any
    loadResponseCountsFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadResponseCountsSuccess: (
        responseCounts: {
            [key: string]: number
        },
        payload?: any
    ) => {
        responseCounts: {
            [key: string]: number
        }
        payload?: any
    }
    loadSurveys: () => any
    loadSurveysFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadSurveysSuccess: (
        surveys: Survey[],
        payload?: any
    ) => {
        surveys: Survey[]
        payload?: any
    }
    setSearchTerm: (searchTerm: string) => {
        searchTerm: string
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface surveyTriggerLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        filteredSurveys: (allSurveys: Survey[], searchTerm: string) => Survey[]
    }
}

export type surveyTriggerLogicType = MakeLogicType<
    surveyTriggerLogicValues,
    surveyTriggerLogicActions,
    Record<string, any>,
    surveyTriggerLogicMeta
>

export const surveyTriggerLogic = kea<surveyTriggerLogicType>([
    path(['products', 'workflows', 'frontend', 'Workflows', 'hogflows', 'registry', 'triggers', 'surveyTriggerLogic']),
    actions({
        setSearchTerm: (searchTerm: string) => ({ searchTerm }),
    }),
    loaders(({ values }) => ({
        surveys: [
            [] as Survey[],
            {
                loadSurveys: async () => {
                    const response = await api.surveys.list({ limit: SURVEYS_PAGE_SIZE, archived: false })
                    return response.results
                },
            },
        ],
        moreSurveys: [
            [] as Survey[],
            {
                loadMoreSurveys: async () => {
                    const response = await api.surveys.list({
                        limit: SURVEYS_PAGE_SIZE,
                        offset: values.allSurveys.length,
                        archived: false,
                    })
                    return response.results
                },
            },
        ],
        responseCounts: [
            {} as Record<string, number>,
            {
                loadResponseCounts: async () => {
                    const surveyIds = values.allSurveys.map((s) => s.id).join(',')
                    if (!surveyIds) {
                        return {}
                    }
                    return await api.surveys.getResponsesCount(surveyIds)
                },
            },
        ],
    })),
    reducers({
        searchTerm: [
            '' as string,
            {
                setSearchTerm: (_, { searchTerm }) => searchTerm,
            },
        ],
        allSurveys: [
            [] as Survey[],
            {
                loadSurveysSuccess: (_, { surveys }) => surveys,
                loadMoreSurveysSuccess: (state, { moreSurveys }) => [...state, ...moreSurveys],
            },
        ],
        hasMoreSurveys: [
            true,
            {
                loadSurveysSuccess: (_, { surveys }) => surveys.length >= SURVEYS_PAGE_SIZE,
                loadMoreSurveysSuccess: (_, { moreSurveys }) => moreSurveys.length >= SURVEYS_PAGE_SIZE,
            },
        ],
    }),
    selectors({
        filteredSurveys: [
            (s) => [s.allSurveys, s.searchTerm],
            (allSurveys: Survey[], searchTerm: string): Survey[] => {
                if (!searchTerm) {
                    return allSurveys
                }
                const lower = searchTerm.toLowerCase()
                return allSurveys.filter((s) => s.name.toLowerCase().includes(lower))
            },
        ],
    }),
    afterMount(({ actions }) => {
        actions.loadSurveys()
    }),
    listeners(({ actions }) => ({
        loadSurveysSuccess: () => {
            actions.loadResponseCounts()
        },
        loadMoreSurveysSuccess: () => {
            actions.loadResponseCounts()
        },
        loadSurveysFailure: ({ error }) => {
            lemonToast.error('Failed to load surveys: ' + error)
        },
        loadMoreSurveysFailure: ({ error }) => {
            lemonToast.error('Failed to load more surveys: ' + error)
        },
        loadResponseCountsFailure: ({ error }) => {
            lemonToast.error('Failed to load response counts: ' + error)
        },
    })),
])
